  1→import { useCallback, useMemo, useState } from 'react';
  2→import { MOCK_COLORS } from '../../data/mock_data';
  3→import { useHUD } from '../../hooks/use_hud';
  4→import { useKeyboardShortcut } from '../../hooks/use_keyboard_shortcut';
  5→import type { ColorItemData } from '../../types';
  6→import { ActionPanel } from '../action_panel/action_panel';
  7→import type { DropdownSection } from '../action_panel/actions_dropdown';
  8→import { EmptyState } from '../empty_state/empty_state';
  9→import { Grid, GridItem } from '../grid';
 10→import { HUDContainer } from '../hud/hud_container';
 11→import { Kbd } from '../kbd/kbd';
 12→import { SearchBar } from '../search_bar/search_bar';
 13→import type { SearchDropdownSection } from '../search_bar/search_dropdown';
 14→import { SearchDropdown } from '../search_bar/search_dropdown';
 15→import './color_picker_view.scss';
 16→
 17→function ClipboardHUDIcon() {
 18→  return (
 19→    <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
 20→      <rect
 21→        x="4"
 22→        y="2"
 23→        width="8"
 24→        height="12"
 25→        rx="1.5"
 26→        stroke="currentColor"
 27→        strokeWidth="1.5"
 28→      />
 29→      <path
 30→        d="M6 2.5H10"
 31→        stroke="currentColor"
 32→        strokeWidth="1.5"
 33→        strokeLinecap="round"
 34→      />
 35→    </svg>
 36→  );
 37→}
 38→
 39→function SearchIcon() {
 40→  return (
 41→    <svg
 42→      width="48"
 43→      height="48"
 44→      viewBox="0 0 48 48"
 45→      fill="none"
 46→      xmlns="http://www.w3.org/2000/svg"
 47→    >
 48→      <circle cx="21" cy="21" r="12" stroke="currentColor" strokeWidth="3" />
 49→      <line
 50→        x1="30"
 51→        y1="30"
 52→        x2="42"
 53→        y2="42"
 54→        stroke="currentColor"
 55→        strokeWidth="3"
 56→        strokeLinecap="round"
 57→      />
 58→    </svg>
 59→  );
 60→}
 61→
 62→function ColorSwatch({ color }: { color: string }) {
 63→  return (
 64→    <div
 65→      className="grid-item__color-swatch"
 66→      style={{ backgroundColor: color }}
 67→    />
 68→  );
 69→}
 70→
 71→function filterColors(colors: ColorItemData[], query: string): ColorItemData[] {
 72→  if (!query) return colors;
 73→  const lower = query.toLowerCase();
 74→  return colors.filter(
 75→    c =>
 76→      c.title.toLowerCase().includes(lower) ||
 77→      c.subtitle?.toLowerCase().includes(lower),
 78→  );
 79→}
 80→
 81→const colorFilterSections: SearchDropdownSection[] = [
 82→  {
 83→    options: [
 84→      {
 85→        label: 'All Colors',
 86→        value: 'all',
 87→      },
 88→    ],
 89→  },
 90→  {
 91→    title: 'Category',
 92→    options: [
 93→      {
 94→        label: 'Warm',
 95→        value: 'warm',
 96→      },
 97→      {
 98→        label: 'Cool',
 99→        value: 'cool',
100→      },
101→      {
102→        label: 'Neutral',
103→        value: 'neutral',
104→      },
105→    ],
106→  },
107→];
108→
109→export function ColorPickerView() {
110→  const [query, setQuery] = useState('');
111→  const [filterValue, setFilterValue] = useState('all');
112→  const [selectedIndex, setSelectedIndex] = useState(0);
113→  const [actionsOpen, setActionsOpen] = useState(false);
114→  const { items: hudItems, show: showHUD } = useHUD();
115→
116→  const filteredColors = useMemo(() => {
117→    let colors: ColorItemData[] = MOCK_COLORS;
118→    if (filterValue !== 'all') {
119→      colors = colors.filter(c => c.category === filterValue);
120→    }
121→    return filterColors(colors, query);
122→  }, [
123→    query,
124→    filterValue,
125→  ]);
126→
127→  const selectedColor = filteredColors[selectedIndex];
128→
129→  const handleQueryChange = useCallback((value: string) => {
130→    setQuery(value);
131→    setSelectedIndex(0);
132→    setActionsOpen(false);
133→  }, []);
134→
135→  const handleFilterChange = useCallback((value: string) => {
136→    setFilterValue(value);
137→    setSelectedIndex(0);
138→  }, []);
139→
140→  const handleActiveIndexChange = useCallback((index: number) => {
141→    setSelectedIndex(index);
142→    setActionsOpen(false);
143→  }, []);
144→
145→  const handleCopyColor = useCallback(
146→    (color: ColorItemData) => {
147→      showHUD({
148→        icon: <ClipboardHUDIcon />,
149→        title: `Copied ${color.color}`,
150→      });
151→    },
152→    [showHUD],
153→  );
154→
155→  const handleGridAction = useCallback(
156→    (index: number) => {
157→      const color = filteredColors[index];
158→      if (color) {
159→        handleCopyColor(color);
160→      }
161→    },
162→    [
163→      filteredColors,
164→      handleCopyColor,
165→    ],
166→  );
167→
168→  const toggleActions = useCallback(() => {
169→    setActionsOpen(prev => !prev);
170→  }, []);
171→
172→  const closeActions = useCallback(() => {
173→    setActionsOpen(false);
174→  }, []);
175→
176→  useKeyboardShortcut(
177→    {
178→      key: 'k',
179→      meta: true,
180→    },
181→    toggleActions,
182→  );
183→
184→  const dropdownSections: DropdownSection[] = useMemo(
185→    () => [
186→      {
187→        title: 'Actions',
188→        actions: [
189→          {
190→            label: 'Copy Color',
191→            shortcut: <Kbd keys={['↵']} />,
192→            onClick: () => {
193→              if (selectedColor) {
194→                setActionsOpen(false);
195→                handleCopyColor(selectedColor);
196→              }
197→            },
198→          },
199→          {
200→            label: 'Copy Hex',
201→            shortcut: (
202→              <Kbd
203→                keys={[
204→                  '⌘',
205→                  'C',
206→                ]}
207→              />
208→            ),
209→            onClick: () => {
210→              if (selectedColor) {
211→                setActionsOpen(false);
212→                showHUD({
213→                  icon: <ClipboardHUDIcon />,
214→                  title: `Copied ${selectedColor.color}`,
215→                });
216→              }
217→            },
218→          },
219→        ],
220→      },
221→    ],
222→    [
223→      selectedColor,
224→      handleCopyColor,
225→      showHUD,
226→    ],
227→  );
228→
229→  const activeDescendantId =
230→    filteredColors.length > 0 ? `grid-item-${selectedIndex}` : undefined;
231→
232→  return (
233→    <>
234→      <SearchBar
235→        value={query}
236→        onChange={handleQueryChange}
237→        activeDescendantId={activeDescendantId}
238→        dropdown={
239→          <SearchDropdown
240→            sections={colorFilterSections}
241→            value={filterValue}
242→            onChange={handleFilterChange}
243→          />
244→        }
245→      />
246→      <div className="color-picker__body">
247→        {filteredColors.length === 0 ? (
248→          <EmptyState
249→            icon={<SearchIcon />}
250→            title="No Colors"
251→            description="Try a different search term"
252→          />
253→        ) : (
254→          <Grid
255→            key={filterValue}
256→            itemCount={filteredColors.length}
257→            columns={4}
258→            onActiveIndexChange={handleActiveIndexChange}
259→            onAction={handleGridAction}
260→          >
261→            {filteredColors.map((color, index) => (
262→              <GridItem
263→                key={color.id}
264→                index={index}
265→                icon={<ColorSwatch color={color.color} />}
266→                title={color.title}
267→                subtitle={color.subtitle}
268→              />
269→            ))}
270→          </Grid>
271→        )}
272→      </div>
273→      <ActionPanel
274→        contextLabel="Color Picker"
275→        actions={[
276→          {
277→            label: 'Copy Color',
278→            shortcut: <Kbd keys={['↵']} />,
279→          },
280→          {
281→            label: 'Actions',
282→            shortcut: (
283→              <Kbd
284→                keys={[
285→                  '⌘',
286→                  'K',
287→                ]}
288→              />
289→            ),
290→            onClick: toggleActions,
291→          },
292→        ]}
293→        dropdownOpen={actionsOpen}
294→        dropdownSections={dropdownSections}
295→        onDropdownClose={closeActions}
296→      />
297→      <HUDContainer items={hudItems} />
298→    </>
299→  );
300→}
301→

